    const tokens = [];
    let i = 0;

    const isSpace = (c) => /\s/.test(c);
    const isDigit = (c) => /[0-9]/.test(c);
    const isIdentStart = (c) => /[A-Za-z_$]/.test(c);
    const isIdentChar = (c) => /[A-Za-z0-9_$]/.test(c);

    while (i < input.length) {
      const ch = input[i];

      if (isSpace(ch)) {
        i++;
        continue;
      }

      if (isDigit(ch) || (ch === "." && isDigit(input[i + 1]))) {
        let start = i;
        i++;
        while (i < input.length && /[0-9.]/.test(input[i])) i++;
        const raw = input.slice(start, i);
        if (!/^\d+(\.\d+)?$|^\.\d+$/.test(raw)) {
          throw new Error(`Invalid number: ${raw}`);
        }
        tokens.push({ type: TOKEN.NUMBER, value: Number(raw) });
        continue;
      }

      if (isIdentStart(ch)) {
        let start = i;
        i++;
        while (i < input.length && (isIdentChar(input[i]) || input[i] === ".")) i++;
        tokens.push({ type: TOKEN.IDENT, value: input.slice(start, i) });
        continue;
      }

      if ("+-*/%".includes(ch)) {
        tokens.push({ type: TOKEN.OP, value: ch });
        i++;
        continue;
      }

      if (ch === "(") {
        tokens.push({ type: TOKEN.LPAREN, value: ch });
        i++;
        continue;
      }

      if (ch === ")") {
        tokens.push({ type: TOKEN.RPAREN, value: ch });
        i++;
        continue;
      }

      throw new Error(`Unexpected character: ${ch}`);
    }

    tokens.push({ type: TOKEN.EOF });
    return tokens;
  }

