function createTemplateEvaluator() {
  const TOKEN_REGEX = /\s*([A-Za-z_$][\w$.]*|\d+(?:\.\d+)?|[()+\-*/%])\s*/g;
  const PLACEHOLDER_REGEX = /{{\s*([^{}]+)\s*}}/g;

  function getPath(obj, path) {
    return path.split(".").reduce((acc, key) => (acc == null ? undefined : acc[key]), obj);
  }

  function tokenize(expr) {
    const tokens = [];
    TOKEN_REGEX.lastIndex = 0;
    let match;
    let consumed = 0;

    while ((match = TOKEN_REGEX.exec(expr)) !== null) {
      tokens.push(match[1]);
      consumed += match[0].length;
    }

    if (consumed !== expr.length) {
      throw new Error(`Invalid token in expression: "${expr}"`);
    }
    return tokens;
  }

  // Shunting-yard: infix -> RPN
  function toRPN(tokens) {
    const out = [];
    const ops = [];
    const prec = { "+": 1, "-": 1, "*": 2, "/": 2, "%": 2 };
    const leftAssoc = { "+": true, "-": true, "*": true, "/": true, "%": true };

    for (const t of tokens) {
      if (/^\d+(?:\.\d+)?$/.test(t) || /^[A-Za-z_$][\w$.]*$/.test(t)) {
        out.push(t);
      } else if (t in prec) {
        while (
          ops.length &&
          ops[ops.length - 1] in prec &&
          ((leftAssoc[t] && prec[t] <= prec[ops[ops.length - 1]]) ||
            (!leftAssoc[t] && prec[t] < prec[ops[ops.length - 1]]))
        ) {
          out.push(ops.pop());
        }
        ops.push(t);
      } else if (t === "(") {
        ops.push(t);
      } else if (t === ")") {
        while (ops.length && ops[ops.length - 1] !== "(") out.push(ops.pop());
        if (!ops.length || ops.pop() !== "(") {
          throw new Error("Mismatched parentheses");
        }
      } else {
        throw new Error(`Unsupported token: ${t}`);
      }
    }

    while (ops.length) {
      const op = ops.pop();
      if (op === "(" || op === ")") throw new Error("Mismatched parentheses");
      out.push(op);
    }

    return out;
  }

  function evalRPN(rpn, data) {
    const stack = [];

