// Deterministic fingerprint for document change detection.
// Same content -> same hash, any content change -> different hash.
function fingerprintDocument(content) {
  if (typeof content !== "string") {
    throw new TypeError("content must be a string");
  }

  // FNV-1a 64-bit hash (fast, stable)
  let hash = 0xcbf29ce484222325n; // offset basis
  const prime = 0x100000001b3n;   // FNV prime
  const mod64 = 0xffffffffffffffffn;

  for (let i = 0; i < content.length; i++) {
    hash ^= BigInt(content.charCodeAt(i));
    hash = (hash * prime) & mod64;
  }

  // Return fixed-width 16-byte hex string
  return hash.toString(16).padStart(16, "0");
}

